/// </summary>
[ExtensionOf(formStr(VendEditInvoice))]
internal final class ETGVendEditInvoiceForm_Extension
{
}

Method.Source:
/// <summary>
/// When submit the vendor invoice via the Workflow , the invoice form should keep the same invoice number.
/// Updating Lines and Vendor invoice after Submit the workflow.
/// </summary>
public void refreshAfterWorkflowSubmit()
{
    next refreshAfterWorkflowSubmit();

    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        VendInvoiceInfoLine_ds.active();
        mainInstructionStaticText.visible(vendInvoiceInfoTable_ds.numberOfRowsLoaded() > 0);

        if (vendInvoiceInfoTable.Num != "" && vendInvoiceInfoTable.PurchName != "")
        {
            mainInstructionStaticText.text(strFmt("%1 : %2", vendInvoiceInfoTable.Num, vendInvoiceInfoTable.PurchName));
        }
        else
        {
            mainInstructionStaticText.text(vendInvoiceInfoTable.Num != "" ? vendInvoiceInfoTable.Num : vendInvoiceInfoTable.PurchName);
        }

        inventDim.data(InventDim::find(vendInvoiceInfoLine.InventDimId));
        vendInvoiceInfoLine.modifyInventDim(inventDim, fieldNum(InventDim,InventLocationId));
    }
}
